  ('medical-tech-moex-09058', 'medical-tech', 'medical-tech-moex-105-483fb9c7', 'sub-medical-tech-01', NULL, 'single_choice', '假設一蛋白質溶液樣本中含有甲和乙兩種蛋白質，且甲和乙之pI值分別為4和6。若該樣本是 以pH值為5的緩衝溶液備製，則甲和乙蛋白質主要各以何種型式存在？', '["兩者皆為不帶電分子", "甲帶正電，乙帶負電", "甲帶負電，乙帶正電", "甲為高極性分子，乙則為低極性分子"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:36+00:00", "source_pdf_sha1": "289c976fe7ab", "answer_pdf_sha1": "9da41c4df739", "source_family": "moex-gov-tw", "moex": {"exam_code": "105020", "c": "308", "s": "55", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生物化學與臨床生化學", "year": "105", "exam_name": "105年第一次醫師牙醫師藥師分階段、藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
